mapper.sql:
FROM diary_image i
INNER JOIN diary d ON d.diary_id = i.diary_id
LEFT JOIN favorite_photo fp ON fp.image_id = i.image_id AND fp.user_id = #{userId}
WHERE d.user_id = #{userId}

    AND d.date >= STR_TO_DATE(#{startDate}, '%Y-%m-%d')


    AND d.date <= STR_TO_DATE(#{endDate}, '%Y-%m-%d')


    AND d.mood_key = #{moodKey}


    AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = d.diary_id AND dt.tag_id = #{tagId})


    AND fp.image_id IS NOT NULL

mapper.select:
SELECT 

ORDER BY d.date DESC, i.sort ASC, i.image_id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT i.image_id, i.diary_id, d.user_id, i.image_path, i.sort, d.title AS diary_title, d.date AS diary_date, d.mood_key, CASE WHEN fp.image_id IS NULL THEN false ELSE true END AS favorite, d.created_at FROM diary_image i INNER JOIN diary d ON d.diary_id = i.diary_id LEFT JOIN favorite_photo fp ON fp.image_id = i.image_id AND fp.user_id = #{userId} WHERE d.user_id = #{userId}
AND i.image_id IN
#{imageId}
AND 1 = 0
ORDER BY d.date ASC, i.sort ASC, i.image_id ASC
